<template>
  <div class="login-container">
    <!-- 头部 -->
    <div class="head">
      <div class="logo-img">
        <img v-if="headerImgUrl" :src="headerImgUrl" />
      </div>
      <h1 class="head-title">{{ headerTitle }}</h1>
    </div>

    <!-- 登录表单 -->
    <el-form
      v-if="page === 'login'"
      :model="modelLogin"
      :rules="loginRules"
      ref="loginForm"
      class="content"
      autocomplete="off"
      @submit.native.prevent
    >
      <el-form-item prop="account">
        <el-input v-model="modelLogin.account" placeholder="手机号" autocomplete="off" prefix-icon="el-icon-mobile-phone" />
      </el-form-item>
      <el-form-item prop="password">
        <el-input v-model="modelLogin.password" placeholder="密码" type="password" autocomplete="off" prefix-icon="el-icon-lock" />
      </el-form-item>
      <el-form-item>
        <el-button type="primary" @click="submitLogin" class="button button-info" :loading="loginLoading">登 录</el-button>
      </el-form-item>
      <el-form-item style="border-bottom: none">
        <el-checkbox v-model="autoLogin" style="color: #1677ff">下次自动登录</el-checkbox>
      </el-form-item>
      <el-form-item style="border-bottom: none">
        <el-button type="text" @click="jump('register')" class="button btn-w-100">去注册</el-button>
      </el-form-item>
    </el-form>

    <!-- 注册表单 -->
    <el-form v-else-if="page === 'register'" :model="modelRegister" :rules="registerRules" ref="registerForm" class="content">
      <el-form-item prop="account">
        <el-input v-model="modelRegister.account" placeholder="手机号" autocomplete="off" prefix-icon="el-icon-mobile-phone" />
      </el-form-item>
      <el-form-item prop="password">
        <el-input v-model="modelRegister.password" placeholder="密码" type="password" autocomplete="off" prefix-icon="el-icon-lock" />
      </el-form-item>
      <el-form-item prop="confirmPassword">
        <el-input v-model="modelRegister.confirmPassword" placeholder="再次确认密码" type="password" prefix-icon="el-icon-lock" />
      </el-form-item>
      <el-form-item>
        <el-button type="primary" @click="submitRegister" class="button button-info" :loading="registerLoading">确 认</el-button>
      </el-form-item>
      <el-form-item style="border-bottom: none">
        <el-checkbox v-model="autoLogin" style="color: #1677ff">下次自动登录</el-checkbox>
      </el-form-item>
      <el-form-item>
        <el-button type="text" @click="jump('login')" class="button btn-w-100">去登录</el-button>
      </el-form-item>
    </el-form>
  </div>
</template>

<script>
import { login, register } from '@/api/login';
import { setToken, getToken, setLocalStorage, getLocalStorage } from '@/utils/auth';
import { getMultiConfig } from '@/api/main';

export default {
  name: 'Login',
  data() {
    return {
      page: 'login', // login or register
      headerImgUrl: require('@/assets/logo.png'),
      headerTitle: '土拨鼠',
      loginLoading: false,
      registerLoading: false,
      autoLogin: true,
      modelLogin: {
        account: '',
        password: ''
      },
      modelRegister: {
        account: '',
        password: '',
        confirmPassword: ''
      },
      loginRules: {
        account: [{ required: true, message: '手机号不能为空', trigger: 'blur' }],
        password: [{ required: true, message: '密码不能为空', trigger: 'blur' }]
      },
      registerRules: {
        account: [{ required: true, message: '手机号不能为空', trigger: 'blur' }],
        password: [{ required: true, message: '密码不能为空', trigger: 'blur' }],
        confirmPassword: [
          { required: true, message: '确认密码不能为空', trigger: 'blur' },
          {
            validator: (rule, value, callback) => {
              if (value !== this.modelRegister.password) {
                callback(new Error('两次密码不一致'));
              } else {
                callback();
              }
            },
            trigger: 'blur'
          }
        ]
      }
    };
  },
  created() {
    if (getToken()) {
      this.switchMain();
      return;
    }
    let loginText = getLocalStorage('autoLoginText');
    if (loginText) {
      let loginTextObj = JSON.parse(loginText);
      this.modelLogin = { account: loginTextObj.account, password: loginTextObj.password };
    }
    this.getConfig();
  },
  methods: {
    getConfig() {
      let params = {
        codeList: ['sys.login']
      };
      getMultiConfig(params).then((response) => {
        const loginConfig = JSON.parse(response.data['sys.login']) || {};
        this.headerImgUrl = loginConfig.logo;
        this.headerTitle = loginConfig.title;
      });
    },
    switchMain() {
      this.$router.push({ name: 'Main' });
    },
    submitLogin() {
      this.$refs.loginForm.validate((valid) => {
        if (valid) {
          this.loginLoading = true;
          // 登录逻辑
          login(this.modelLogin)
            .then((response) => {
              this.loginLoading = false;
              this.$message.success('登录成功！');
              if (this.autoLogin) {
                setLocalStorage('autoLoginText', JSON.stringify(this.modelLogin));
              }
              this.modelLogin = { account: '', password: '' };
              setToken(response.data);
              this.switchMain();
            })
            .catch((_) => {
              this.loginLoading = false;
            });
        }
      });
    },
    submitRegister() {
      this.$refs.registerForm.validate((valid) => {
        if (valid) {
          this.registerLoading = true;
          // 注册逻辑
          register(this.modelRegister)
            .then((response) => {
              this.registerLoading = false;
              this.$message.success('注册成功！');
              if (this.autoLogin) {
                let data = { account: this.modelRegister.account, password: this.modelRegister.password };
                setLocalStorage('autoLoginText', JSON.stringify(data));
              }
              this.modelRegister = { account: '', password: '', confirmPassword: '' };
              this.jump('login');
            })
            .catch((_) => {
              this.registerLoading = false;
            });
        }
      });
    },
    jump(page) {
      // 只清除验证状态，不触发字段变更
      const currentForm = this.page === 'login' ? 'loginForm' : 'registerForm';
      this.$refs[currentForm] && this.$refs[currentForm].clearValidate();
      // 手动重置 model 数据
      if (this.page === 'login') {
        let loginText = getLocalStorage('autoLoginText');
        if (loginText) {
          let loginTextObj = JSON.parse(loginText);
          this.modelLogin = { account: loginTextObj.account, password: loginTextObj.password };
        }
      } else {
        this.modelRegister = { account: '', password: '', confirmPassword: '' };
      }
      this.page = page;
      // DOM 切换后清除新表单可能残留的验证状态
      this.$nextTick(() => {
        const nextForm = page === 'login' ? 'loginForm' : 'registerForm';
        this.$refs[nextForm] && this.$refs[nextForm].clearValidate();
      });
    }
  }
};
</script>

